create extension if not exists pgcrypto;

create table if not exists activities (
  id uuid primary key default gen_random_uuid(),
  day int not null,
  month int not null default 7,
  title text not null,
  tag text not null,
  type text not null default 'd',
  description text not null,
  task text not null,
  how_to text not null,
  collect text not null,
  send_to_admin text not null,
  estimated_minutes int not null default 60,
  is_active boolean not null default true,
  sort_order int not null default 0
);

create table if not exists assignments (
  id uuid primary key default gen_random_uuid(),
  activity_id uuid not null references activities(id) on delete cascade,
  volunteer_name text not null,
  status text not null default 'Взято в работу',
  planned_minutes int,
  spent_minutes int,
  material_link text,
  volunteer_comment text,
  admin_comment text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table activities enable row level security;
alter table assignments enable row level security;

drop policy if exists "public read activities" on activities;
create policy "public read activities" on activities for select using (true);

drop policy if exists "public read assignments" on assignments;
create policy "public read assignments" on assignments for select using (true);

truncate table assignments restart identity cascade;
truncate table activities restart identity cascade;

insert into activities (day,title,tag,type,description,task,how_to,collect,send_to_admin,estimated_minutes,sort_order) values
(8,'Старт Добро.Медиа + День семьи','Старт','r','Начинаем работу медиабюро и используем День семьи как тёплый повод для первого июльского материала.','Выбери небольшой семейный или добрый сюжет: поздравление, семейная традиция, помощь родным, тёплый летний момент.','Не делай большой официальный отчёт. Лучше одна живая история, 5–7 хороших кадров и короткий текст.','Фото или короткое видео, дата, место, 2–3 факта, если есть — реальный комментарий.','Отправь Евгению Валерьевичу фото/видео, черновик текста и подпись: где и когда снято.',60,8),
(9,'Собственная тема','Своя тема','d','День для самостоятельного сюжета: человек, место, летняя деталь, доброе дело или маленькое событие Кеми.','Выбери одну тему и попробуй собрать по ней мини-репортаж.','Сначала сформулируй, почему это интересно. Потом сними общий план, детали и эмоцию.','5–7 фото или 2–3 коротких видео, название места, дата, короткое описание.','Отправь комплект и напиши, почему выбрал(а) эту тему.',45,9),
(10,'Собственная тема','Своя тема','d','Продолжаем тренироваться на свободной теме без привязки к акции.','Собери визуальный материал: фото, короткое видео или основу для поста.','Не снимай всё подряд. Выбери один сюжет: место, человек, действие, настроение.','Фото/видео, 3–5 фактов или наблюдений, возможный заголовок.','Отправь материалы и короткий черновик подписи.',45,10),
(11,'Первые лица','Интервью','b','Рубрика о людях Движения: активистах, волонтёрах, наставниках, участниках событий.','Найди героя и задай 3 коротких вопроса.','Вопросы простые: чем занимаешься, что запомнилось, почему это важно, что хочешь пожелать ребятам.','Фото героя, имя, 2–3 реальных ответа, место или событие.','Отправь ответы без выдуманных цитат и 2–3 фото.',60,11),
(12,'Материал по выбранной теме','Материал','d','День, чтобы довести до черновика один из уже выбранных сюжетов.','Собери материал в понятную форму: пост, подборка фото или короткий ролик.','Проверь факты: дата, место, имена, что происходило и почему это важно.','Черновик текста, 7–10 фото или короткий ролик, подписи к материалам.','Отправь Евгению Валерьевичу готовый черновик и файлы.',60,12),
(13,'Лица Кеми','Лица Кеми','b','Истории людей, через которых видно жизнь Кеми: активисты, жители, родители, педагоги, волонтёры, работники культуры.','Найди человека, о котором можно рассказать добрую или важную историю.','Будь уважителен. Спроси разрешение, задай 3 вопроса, не придумывай ответы.','Имя, род деятельности, фото, 2–3 ответа, почему этот человек важен для темы.','Отправь мини-историю и укажи, можно ли использовать фото и имя.',60,13),
(14,'Проект за минуту','О проекте','d','Короткое объяснение, что такое Добро.Медиа и зачем нужна медиакоманда.','Подготовь простой пост или карточку: кто мы, что делаем, как участвовать.','Пиши для ровесников: без канцелярита, коротко, понятно и дружелюбно.','3–5 тезисов, черновик текста, идея визуала.','Отправь черновик и предложи, какую картинку можно поставить.',45,14),
(15,'Анонс «Великого Флота»','Анонс','r','Готовим аудиторию к морской акции «Великий Флот».','Сделай черновик анонса: когда, о чём акция, почему это интересно для Кемского округа.','Добавь локальный смысл: Кемь, Белое море, морская история, северное настроение.','Черновик анонса, 1–2 идеи кадров, возможные хештеги.','Отправь текст анонса и идеи визуала.',45,15),
(16,'Кемь и море','Кемь','b','Локальный материал о связи Кеми, Рабочеостровска, Белого моря и морской темы.','Собери небольшой материал про море рядом с нами.','Можно снять берег, детали, настроение, людей у воды, но без опасных мест и риска.','Фото/видео, место съёмки, 2–3 наблюдения, короткий текст.','Отправь материалы и подпиши, где снято.',60,16),
(17,'Своя тема: морской ракурс','Своя тема','d','Свободный день для морской или летней темы.','Выбери свой ракурс: море, берег, корабли, ветер, север, летнее настроение.','Лучше одна точная деталь, чем общий текст обо всём.','5–7 фото, короткое видео или черновик поста.','Отправь материал с пометкой «морской ракурс».',45,17),
(18,'Своя тема: летняя история','Своя тема','d','День для небольшой летней истории без привязки к организациям.','Найди сюжет: прогулка, помощь, встреча, творческая деталь, красивое место.','Покажи событие через действие и настроение.','Фото/видео, короткий текст, дата и место.','Отправь материалы на проверку.',45,18),
(19,'Своя тема: люди и места','Своя тема','d','Локальный сюжет о людях и местах Кемского округа.','Выбери место или человека, через которого можно рассказать историю.','Сними уважительно, не мешай людям, спрашивай разрешение при портретах.','Фото, короткое описание, если есть — комментарий героя.','Отправь комплект материалов и вопросы, если нужно уточнение.',60,19),
(20,'Напоминание о «Великом Флоте»','Напоминание','b','Последний день подготовки к старту морской акции.','Подготовь короткое напоминание или заготовку к первому посту.','Текст должен быть коротким: что начинается, зачем участвовать, что будет интересно.','Черновик напоминания, идея картинки или сторис.','Отправь текст и предложи вариант визуала.',35,20),
(21,'«Великий Флот»: старт','Великий Флот','r','Старт морской акции. Нужны первые кадры, атмосфера и короткое объяснение, что происходит.','Собери первые фото, видео и один короткий комментарий.','Сними общий план, детали, действия участников и эмоции.','5–10 фото, 2–3 видео, 1 комментарий, дата и место.','Отправь комплект с темой «Великий Флот: старт».',75,21),
(22,'Своя тема','Своя тема','d','Свободный день для самостоятельного материала без обязательной акции.','Выбери любой подходящий сюжет и собери мини-материал.','Проверь, чтобы тема была доброй, понятной и безопасной для публикации.','Фото/видео, черновик текста, дата и место.','Отправь материалы Евгению Валерьевичу.',45,22),
(23,'Выставка / творческие работы','Творчество','b','Если есть материалы по «Великому Флоту», можно показать рисунки, плакаты, поделки или другие творческие работы.','Сними работы, детали и авторов, если есть разрешение.','Не фотографируй личные данные. Работы снимай ровно, без бликов и обрезанных краёв.','Фото работ, общее фото, название площадки, авторы при возможности.','Отправь подборку и подписи к работам.',60,23),
(24,'Лаборатория воды / морские задания','Видео','b','Материал о процессе: опыты, задания, подготовка, реакции, детали.','Сними короткие видео для ролика.','Держи телефон устойчиво, снимай по 5–10 секунд, чередуй общий план и детали.','5–7 видео, 5 фото, короткое описание происходящего.','Отправь видеофрагменты и идею монтажа.',75,24),
(25,'Интервью участников','Интервью','b','Собираем реальные впечатления участников.','Возьми 2–3 коротких комментария.','Спроси: что запомнилось, что нового узнали, какое настроение после события.','Ответы участников, имена при разрешении, 2–3 фото.','Отправь реальные ответы без художественных вставок.',60,25),
(26,'Итоги «Великого Флота»','Итоги','r','Собираем финальный материал по морской акции.','Выбери лучшие материалы и подготовь черновик итогового поста.','В итогах важно показать смысл, людей, результат и благодарность.','10–15 фото, 1–2 видео, факты, благодарности, черновик текста.','Отправь полный комплект на проверку.',90,26),
(27,'Готовим август: «Физкульт-привет»','Август','r','Заранее готовим идеи к спортивной августовской акции.','Придумай идею поста, ролика или карточки про спорт и движение.','Думай про энергию: зарядка, команда, поддержка, улыбки, движение.','Идея поста/ролика, 3–5 возможных кадров, короткий анонс.','Отправь заготовку к «Физкульт-привет».',45,27),
(28,'Задание к «Физкульт-привет»','Август','b','Делаем конкретный черновик к спортивной теме.','Подготовь один материал: анонс, текст карточки или короткий сценарий ролика.','Не делай чек-лист. Сделай именно заготовку, которую можно будет использовать в августе.','Черновик текста или сценария, идеи кадров, возможный заголовок.','Отправь готовую заготовку.',60,28),
(29,'Готовим август: «Забота о меньших»','Август','r','Подготовка доброго контента о помощи животным.','Придумай материал о заботе: история, карточка, пост или фотоидея.','Тон должен быть бережным: не давим на жалость, показываем ответственную помощь.','Идея поста, возможные герои, вопросы для короткого интервью, визуальная идея.','Отправь заготовку к акции «Забота о меньших».',60,29),
(30,'Готовим август: «Символ народа»','Август','r','Подготовка уважительного контента ко Дню Государственного флага России.','Придумай светлый и аккуратный материал о флаге.','Избегай перегруза. Тон — уважительный, спокойный, торжественный.','Черновик анонса, идеи фото, 2–3 вопроса участникам, возможный заголовок.','Отправь заготовку к акции «Символ народа».',60,30),
(31,'Итоги июля + готовность к августу','Итоги','r','Закрываем июль и собираем всё, что подготовлено к августу.','Собери список выполненных материалов и заготовок.','Проверь, что всё понятно подписано: дата, тема, автор, ссылка на файлы.','Список материалов, лучшие фото, заготовки к августу, вопросы к куратору.','Отправь итоговый комплект Евгению Валерьевичу.',75,31);
